INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (1, '小钱袋', '装有少量金币的袋子。', 1, '使用：获得 1000 金币。', 0, 1, NULL, 'ADD_COINS', '{"amount": 1000}');
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (2, '中号钱袋', '沉甸甸的钱袋，里面装着不少金币。', 2, '使用：获得 10000 金币。', 0, 1, NULL, 'ADD_COINS', '{"amount": 10000}');
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (3, '大号钱袋', '鼓鼓囊囊的大钱袋，非常重。', 3, '使用：获得 50000 金币。', 0, 1, NULL, 'ADD_COINS', '{"amount": 50000}');
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (4, '神秘钱袋', '会变换重量的神秘钱袋，谁也不知道里面有多少钱。', 4, '使用：随机获得 5000 至 20000 金币。', 0, 1, NULL, 'ADD_COINS', '{"min_amount": 5000, "max_amount": 20000}');
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (5, '巨型钱袋', '仿佛装满了全世界财富的巨大袋子。', 5, '使用：随机获得 100000 至 500000 金币！', 0, 1, NULL, 'ADD_COINS', '{"min_amount": 100000, "max_amount": 500000}');
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (6, '龙之钱袋', '据说是龙看见了也会两眼发光的超大钱袋。', 6, '使用：随机获得 1000000 至 5000000 金币！', 0, 1, NULL, 'ADD_COINS', '{"min_amount": 1000000, "max_amount": 5000000}');
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (7, '擦弹许可证', '官方发放的许可证，允许你今天额外进行1次擦弹。', 6, '使用：今天可用的擦弹次数增加1次。', 0, 1, NULL, 'WIPE_BOMB_ATTEMPTS_BOOST', '{"amount": 1}');
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (8, '归元护符', '成败自有天命，大道自有归途。归元法印，精炼崩毁时会牵回本体残机，虽会折损一重境界，却不至彻底毁坏。', 7, '获得1次基本保护（使用后，进行精炼时自动生效。毁坏时改为降一级并保留本体）。', 0, 0, NULL, 'REFINE_DESTRUCTION_SHIELD', '{"mode": "downgrade"}');
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (9, '晨星祝福徽记', '星辉抵抗灾厄，将毁坏改写为安然无损的失败。', 8, '获得1次精炼保护（使用后，进行精炼时自动生效。毁坏时改判为普通失败，本体保留不降级）。', 0, 0, NULL, 'REFINE_DESTRUCTION_SHIELD', '{"mode": "keep"}');
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (10, '零点保险协议', '一次性量子保险协议，会在精炼判定异常时锁定装备基准态，强制将失败结算压回安全结果。', 9, '获得1次至高保护（使用后，进行精炼时自动生效。任何失败时必改为普通失败，本体保留不降级）。', 0, 0, NULL, 'REFINE_DESTRUCTION_SHIELD', '{"mode": "keep"}');
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (11, '鱼甄选交换凭证', '鱼甄选回收部发放的统一回收货币，用于证明你的研究资质。', 6, '可用于兑换区域通行证。', 0, 0, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (12, '鱼光临海域通行证', '由“鱼光临”渔具有限公司发放的一次性通行证，持有此证将被允许进入受其管辖的海域。', 5, '凭此证可进入鱼光临海域。', 0, 1, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (13, '鱼光临养殖区通行证', '另一张一次性通行证，据说养殖的鱼类因为活得太滋润导致大量繁殖，他们才迫不得已开放出来让人钓。', 6, '凭此证可进入鱼光临养殖区。', 0, 1, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (14, '工厂污染区域通行证', '你被允许前往该海域的放行理由是能通过钓鱼净化水质。', 7, '可凭此证可进入污染区域。', 0, 1, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (15, '化龙碎片', '化为龙的鲤鱼褪下的残壳碎片。', 7, '可凭此碎片登上龙瀑之巅。', 0, 1, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (16, '千面碎片', '千百种生物皮肤的细小碎片。', 7, '可凭此碎片靠近深渊漩涡。', 0, 1, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (17, '龙窟金币', '因沾染到龙息，有些许融化的普通金币。', 7, '可凭此碎片踏入龙之洞窟。', 0, 1, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (18, '海峡地图', '乱开船乱开车可找不到大家常说的入门海峡在哪。', 5, '可永久进入特定钓鱼区域。', 0, 0, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (19, '鱼光临海域通行证（终身VIP）', '本公司海域将永远为您开放！招牌里还会写上您的名字！您是我们的神！把钱给我们！', 6, '可永久进入特定钓鱼区域。', 0, 0, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (20, '鱼光临养殖区通行证（VIP客户专供）', '其实原本用另外一张终身VIP证就可以去的…但上面临时又推出了一种通行证……没想到真的会有人买的大嘴巴员工（第二天被开了）如是说。', 7, '可永久进入特定钓鱼区域。', 0, 0, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (21, '工厂污染区域通行证（时空错乱）', '这里究竟是未来，还是以前？你唯独能确信的就是这里并非现在。', 10, '可永久进入特定钓鱼区域。', 0, 0, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (22, '化龙碎片（磨砺锋芒）', '鲤鱼化龙时，被龙瀑打磨锋利的鳞片碎片。即可伤及自身，亦可割开瀑布；若惧怕伤痛，则无法凭此鳞逆流而上。', 10, '可永久进入特定钓鱼区域。', 0, 0, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (23, '千面碎片（血液凝固）', '被凝固的血液粘在一起，忘记了自己究竟是谁；再也无法分开的千种脸面的碎片。', 10, '可永久进入特定钓鱼区域。', 0, 0, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (24, '龙窟金币（龙息淬炼）', '被龙息融化千万枚后才能淬出的一枚，其滚烫余温至今都还未散尽。', 10, '可永久进入特定钓鱼区域。', 0, 0, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (25, '高级犬尾草冻干狗粮', '献给某些生物即可获得自定义专属称号。', 9, '持有该物品并想办法告诉它你想要的称号，静候神秘生物前来回收即可。', 0, 0, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (26, '科考许可证（探险）', '由鱼寻思鱼类进化研究有限公司发放的科学考察许可证，他们的业务覆盖是不是有点太广了…', 7, '可发起探险级科考活动。', 0, 1, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (27, '科考许可证（征服）', '对鱼光临的科研团队而言，稳定的特定鱼类获取渠道是非常重要的。仅发放给积累了一定科考实绩的钓鱼佬。', 8, '可发起征服级科考活动。', 0, 1, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (28, '科考许可证（圣域）', '传闻中的巨型科研团队所需的巨量特定鱼类只有极巨的钓鱼佬团队才能完成的巨难的科考任务。', 9, '可发起圣域级科考活动。', 0, 1, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (29, '科考通行证', '要想加入科研团队的话，必须持有的证件。你感觉被他们两头赚了。', 6, '可加入任意科考活动。', 0, 1, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (30, '称号·鱼甄选CEO', '鱼甄选只把这名号颁给交付过珍品的客户。它不折算凭证，不打折，不找零，没权力没薪水没持股，只证明您确实见过大场面。', 9, '使用后获得称号：鱼甄选CEO', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (31, '称号·观测锚点', '为便于运输免费提供鱼类隔离舱，但无法保障碳基肢体的时空连续性。回收价将视当前维度稳定性收取稳定税与观测费。', 9, '使用后获得称号：观测锚点', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (32, '称号·万机之神', '回收目标：自成长AI-WL-GQ型；拟态破解方程式：量子筛选；冲突损毁补贴：无；交换品项：荣耀。', 9, '使用后获得称号：万机之神', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (33, '称号·星际收藏', '文明墓碑、恒星雏形、引力异常体、熵增残响。科研与收藏价值极高。提交时请隔离存放。', 9, '使用后获得称号：星际收藏', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (34, '称号·生态武装·维度防线', '某些文明建造全自动化工厂阻拦外敌的可能性，由该类可能性构成的多种时间线无法直接观测。感谢您的帮助，该项目名将作为名号转让。', 9, '使用后获得称号：生态武装·维度防线', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (35, '称号·天地劫火', '集炎火为灵之生命，热浪蒸腾，海水沸响，自成一座微缩的暴怒天地。', 9, '使用后获得称号：天地劫火', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (36, '称号·一方霸主', '霸主生灵虎视蠢动，如今在争夺残骸的大战中交汇。', 9, '使用后获得称号：一方霸主', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (37, '称号·寻龙冢', '曾有一缕不灭残魄，以魂灯盗寿命，以断剑斩仙泪。寻龙之途遥遥，迷失永无天日。', 9, '使用后获得称号：寻龙冢', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (38, '称号·寻天道', '何为道？何为天道？不过万物，不过你我。', 9, '使用后获得称号：寻天道', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (39, '称号·存在与不存在之物', '那些只不过是尘埃的鱼类，堆积成了通往深渊的阶梯。', 9, '使用后获得称号：存在与不存在之物', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (40, '称号·别看了。', '别看了。', 9, '使用后获得称号：别看了。', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (41, '称号·吞噬万物', '被死有余辜之物吞噬，然后大汗淋漓地醒来。', 9, '使用后获得称号：吞噬万物', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (42, '称号·创造万物', '那是起源者，又或只是破坏者？', 9, '使用后获得称号：创造万物', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (43, '称号·白金之剑', '此称号证明你的鱼竿将为善龙神巴哈姆特而挥动，从此与五色龙种不共戴天。', 10, '使用后获得称号：白金之剑', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (44, '称号·五彩之爪', '此称号证明你的鱼竿将为邪龙神提亚马特而挥动，从此与金属龙种不共戴天。', 10, '使用后获得称号：五彩之爪', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (45, '称号·至高妖精', '此称号证明你的鱼竿将为妖精王而挥动，从此……开始看善邪龙打架的好戏。', 10, '使用后获得称号：至高妖精', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (46, '称号·元素后裔', '此称号证明你的鱼竿将为……算了，四元素都还打得不可开交呢。', 10, '使用后获得称号：元素后裔', 0, 1, NULL, 'GRANT_TITLE_TBD', NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (47, '星屑', '金币被投入黑洞后被压缩再吐出的微光碎片，边缘仍残留着不稳定的数据噪声。', 6, '用于兑换特殊装备。', 0, 0, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (48, '星核', '钻石在极端引力与高能压缩下凝成的核心结晶，内部封存着一段尚未熄灭的恒星脉冲。', 8, '用于兑换特殊装备。', 0, 0, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (49, '道屑', '金币在大道流转时化为的一缕残痕，细若尘埃，却仍隐隐映照天机。', 6, '用于兑换特殊装备。', 0, 0, NULL, NULL, NULL);
INSERT INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "icon_url", "effect_type", "effect_payload") VALUES (50, '道晶', '钻石被道痕凝练、灵机内敛所成的晶体，通体澄澈，却有万千法则在其中沉浮流转。', 8, '用于兑换特殊装备。', 0, 0, NULL, NULL, NULL);
